%[text] # Closed-Loop Step Response Analysis
%[text] Loads an ArduPilot `.mat` log, plots the setpoint, measured response, control effort, and PID controller internals for a speed or yaw-rate step experiment, then applies `stepinfo` to quantify rise time, settling time, overshoot, and steady-state error.
%[text] ## 1 — User Input
%[text] Set the log file path and which controller to analyze, then run all sections top to bottom.
clear;

fname      = "your_log.mat";  % path to .mat file produced by bin2mat.py
experiment = "speed";         % "speed"  →  surge (m/s)  |  "yaw"  →  yaw rate (rad/s)

% Tuning
fdir = "/Users/brian.bingham/WorkingCopies/me2801/2026_05_06_tuning/";
% A - FF only
% Speed
fname = fullfile(fdir, "00000011.BIN_20260506_223549.mat");
experiment = "speed";
% Yaw-rate
fname = fullfile(fdir, "00000013.BIN_20260506_223627.mat");
experiment = "yaw";
%  B - FF and PID
% Speed
fname = fullfile(fdir, "00000015.BIN_20260506_223900.mat");
experiment = "speed";
% Yaw
fname = "/Users/brian.bingham/WorkingCopies/me2801/2026_05_06_boat_tests/2026_05_06_tuning/00000017.BIN_20260506_223937.mat";%fullfile(fdir, "00000017.BIN_20260506_223937.mat");
experiment = "yaw";

%[text] ## 2 — Load
fprintf("Loading %s ...\n", fname); %[output:723909ef]
d = load(fname);

[dirpath, name, ext] = fileparts(fname);
[~, lastDir] = fileparts(dirpath);
fileLabel = fullfile(lastDir, sprintf("%s.%s", name, ext));
%%
%[text] ## PID Parameters
if isfield(d, "params")
    p = d.params;
    fprintf("\n--- Surge speed PID (ATC_SPEED_*) ---\n");
    fprintf("  P: %g    I: %g    D: %g    FF: %g\n", ...
        p.ATC_SPEED_P, p.ATC_SPEED_I, p.ATC_SPEED_D, p.ATC_SPEED_FF);
    fprintf("\n--- Yaw-rate PID (ATC_STR_RAT_*) ---\n");
    fprintf("  P: %g    I: %g    D: %g    FF: %g\n", ...
        p.ATC_STR_RAT_P, p.ATC_STR_RAT_I, p.ATC_STR_RAT_D, p.ATC_STR_RAT_FF);
else
    fprintf("No params struct — reprocess .BIN with updated bin2mat.py\n");
end
%[text] ## 3 — Signals
% Elapsed seconds from the earliest message across all channels
t0 = min([d.THR_timestamp(1), d.GPS_timestamp(1), ...
          d.STER_timestamp(1), d.RCOU_timestamp(1)]);

t_thr  = d.THR_timestamp  - t0;
t_gps  = d.GPS_timestamp  - t0;
t_ster = d.STER_timestamp - t0;
t_rcou = d.RCOU_timestamp - t0;

% PID internal log messages (PIDS = steering/yaw-rate, PIDT = throttle/speed)
has_pids = isfield(d, "PIDS_timestamp");
has_pidt = isfield(d, "PIDT_timestamp");
if has_pids, t_pids = d.PIDS_timestamp - t0; end
if has_pidt, t_pidt = d.PIDT_timestamp - t0; end

% PWM → normalized effort (piecewise; adjust inzero/inmax/inmin to match vehicle params)
inzero = 1500;  inmax = 1900;  inmin = 1100;
throttle_norm = normalize_pwm(d.RCOU_C3, inzero, inmax, inmin);
rudder_norm   = normalize_pwm(d.RCOU_C1, inzero, inmax, inmin);
%[text] ## 4 — Full Timeseries
%[text] Figure 1: setpoint, measured response, and control effort.  Figure 2: PID controller internals (Tar/Act, P/I/D/FF terms, total output).  Inspect both to find the elapsed-second boundaries of the step; enter those values in Section 5.
if experiment == "speed" %[output:group:1fbda6ff]
    figure(1); clf();
    ax1 = subplot(211);
    hold on;
    plot(t_thr, d.THR_DesSpeed, "b--", "DisplayName", "Setpoint");
    plot(t_gps, d.GPS_Spd,      "r-",  "DisplayName", "Measured (GPS)");
    hold off;
    ylabel("Speed (m/s)");
    legend("Location", "best");
    title(sprintf("Surge Step Response — %s", fileLabel), "Interpreter", "none");
    grid on;
    ax2 = subplot(212);
    plot(t_rcou, throttle_norm, "k-", "DisplayName", "Throttle");
    ylabel("Throttle effort (norm.)");
    ylim([-1.05, 1.05]);
    xlabel("Elapsed time (s)");
    legend("Location", "best");
    grid on;
    linkaxes([ax1, ax2], "x");

    if has_pidt
        figure(2); clf();
        ax1 = subplot(311);
        hold on;
        plot(t_pidt, d.PIDT_Tar, "b--", "DisplayName", "Target");
        plot(t_pidt, d.PIDT_Act, "r-",  "DisplayName", "Actual");
        hold off;
        ylabel("Speed (m/s)");
        legend("Location", "best");
        title(sprintf("Speed PID Internals — %s", fileLabel), "Interpreter", "none");
        grid on;
        ax2 = subplot(312);
        hold on;
        plot(t_pidt, d.PIDT_P,  "b-",  "DisplayName", "P");
        plot(t_pidt, d.PIDT_I,  "g-",  "DisplayName", "I");
        plot(t_pidt, d.PIDT_D,  "r-",  "DisplayName", "D");
        plot(t_pidt, d.PIDT_FF, "m--", "DisplayName", "FF");
        hold off;
        ylabel("PID terms");
        legend("Location", "best");
        grid on;
        ax3 = subplot(313);
        plot(t_pidt, d.PIDT_Out, "k-", "DisplayName", "Output");
        ylabel("PID output");
        xlabel("Elapsed time (s)");
        legend("Location", "best");
        grid on;
        linkaxes([ax1, ax2, ax3], "x");
    else
        fprintf("PIDT messages not found in log — no speed PID internals plot.\n");
    end
else
    figure(1); clf(); %[output:30cf2de0]
    ax1 = subplot(211); %[output:30cf2de0]
    hold on; %[output:30cf2de0]
    plot(t_ster, d.STER_DesTurnRate, "b--", "DisplayName", "Setpoint"); %[output:30cf2de0]
    plot(t_ster, d.STER_TurnRate,    "r-",  "DisplayName", "Measured"); %[output:30cf2de0]
    hold off; %[output:30cf2de0]
    ylabel("Yaw rate (rad/s)"); %[output:30cf2de0]
    legend("Location", "best"); %[output:30cf2de0]
    title(sprintf("Yaw-Rate Step Response — %s", fileLabel), "Interpreter", "none"); %[output:30cf2de0]
    grid on; %[output:30cf2de0]
    ax2 = subplot(212); %[output:30cf2de0]
    plot(t_rcou, rudder_norm, "k-", "DisplayName", "Rudder"); %[output:30cf2de0]
    ylabel("Rudder effort (norm.)"); %[output:30cf2de0]
    ylim([-1.05, 1.05]); %[output:30cf2de0]
    xlabel("Elapsed time (s)"); %[output:30cf2de0]
    legend("Location", "best"); %[output:30cf2de0]
    grid on; %[output:30cf2de0]
    linkaxes([ax1, ax2], "x"); %[output:30cf2de0]

    if has_pids
        figure(2); clf(); %[output:30cf2de0]
        ax1 = subplot(311); %[output:30cf2de0]
        hold on; %[output:30cf2de0]
        plot(t_pids, d.PIDS_Tar, "b--", "DisplayName", "Target"); %[output:30cf2de0]
        plot(t_pids, d.PIDS_Act, "r-",  "DisplayName", "Actual"); %[output:30cf2de0]
        hold off; %[output:30cf2de0]
        ylabel("Yaw rate (rad/s)"); %[output:30cf2de0]
        legend("Location", "best"); %[output:30cf2de0]
        title(sprintf("Yaw-Rate PID Internals — %s", fileLabel), "Interpreter", "none"); %[output:30cf2de0]
        grid on; %[output:30cf2de0]
        ax2 = subplot(312); %[output:30cf2de0]
        hold on; %[output:30cf2de0]
        plot(t_pids, d.PIDS_P,  "b-",  "DisplayName", "P"); %[output:30cf2de0]
        plot(t_pids, d.PIDS_I,  "g-",  "DisplayName", "I"); %[output:30cf2de0]
        plot(t_pids, d.PIDS_D,  "r-",  "DisplayName", "D"); %[output:30cf2de0]
        plot(t_pids, d.PIDS_FF, "m--", "DisplayName", "FF"); %[output:30cf2de0]
        hold off; %[output:30cf2de0]
        ylabel("PID terms"); %[output:30cf2de0]
        legend("Location", "best"); %[output:30cf2de0]
        grid on; %[output:30cf2de0]
        ax3 = subplot(313); %[output:30cf2de0]
        plot(t_pids, d.PIDS_P + d.PIDS_I + d.PIDS_D + d.PIDS_FF, "k-", "DisplayName", "Output"); %[output:30cf2de0]
        ylabel("PID output"); %[output:30cf2de0]
        xlabel("Elapsed time (s)"); %[output:30cf2de0]
        legend("Location", "best"); %[output:30cf2de0]
        grid on; %[output:30cf2de0]
        linkaxes([ax1, ax2, ax3], "x"); %[output:30cf2de0]
    else
        fprintf("PIDS messages not found in log — no yaw-rate PID internals plot.\n");
    end
end %[output:group:1fbda6ff]
%%
%[text] ## 5 — Step Isolation
%[text] Read `t_step_start` and `t_step_end` from the figures (elapsed seconds from the log start), set them here, then run the remaining sections.
t_step_start = 19.8602  % ← elapsed seconds at step onset %[output:2c031081]
t_step_end   = t_step_start+5;  % ← elapsed seconds when response has settled
%%
%[text] ## 6 — Step Response Metrics
%[text] `stepinfo` uses the 2% settling criterion.  Steady-state error is the mean of the last 20% of the window compared to the commanded setpoint.
if experiment == "speed"
    mask_y  = t_gps >= t_step_start & t_gps <= t_step_end;
    mask_sp = t_thr >= t_step_start & t_thr <= t_step_end;
    t_y     = t_gps(mask_y) - t_step_start;
    y       = d.GPS_Spd(mask_y);
    sp      = d.THR_DesSpeed(mask_sp);
    y_final = sp(end);
    unitStr = "m/s";
    chanStr = "Speed";
else
    mask_y  = t_ster >= t_step_start & t_ster <= t_step_end;
    t_y     = t_ster(mask_y) - t_step_start;
    y       = d.STER_TurnRate(mask_y);
    sp      = d.STER_DesTurnRate(mask_y);
    y_final = sp(end);
    unitStr = "rad/s";
    chanStr = "Yaw rate";
end

y_init = y(1);
S = stepinfo(y(:), t_y(:), y_final, y_init);

n_tail       = max(1, round(0.2 * numel(y)));
y_ss         = mean(y(end - n_tail + 1 : end));
ss_error     = y_final - y_ss;
ss_error_pct = 100 * ss_error / abs(y_final);

fprintf("\n=== %s step-response metrics ===\n", chanStr); %[output:87d8d901]
fprintf("  Setpoint:              %.4f %s\n", y_final, unitStr); %[output:730d9025]
fprintf("  Rise time (10%%–90%%):  %.3f s\n",  S.RiseTime); %[output:04603b4d]
fprintf("  Settling time (2%%):    %.3f s\n",  S.SettlingTime); %[output:5695a296]
fprintf("  Overshoot:             %.1f %%n",  S.Overshoot); %[output:2daf8a4e]
fprintf("  Steady-state value:    %.4f %s\n",  y_ss, unitStr); %[output:453ba339]
fprintf("  Steady-state error:    %.4f %s  (%.1f %%)\n", ss_error, unitStr, ss_error_pct); %[output:7088e683]
%%
%[text] ## 7 — Step Response Plots
%[text] Figure 3: isolated step window (setpoint, measured, steady-state mean).  Figure 4: PID internals over the same window.
figure(3); clf(); %[output:253d8ace]
hold on; %[output:253d8ace]
plot(t_y, y, "r-", "DisplayName", "Measured"); %[output:253d8ace]
yline(y_final, "b--", "Setpoint",     "LabelHorizontalAlignment", "left"); %[output:253d8ace]
yline(y_ss,    "g:",  "Steady state", "LabelHorizontalAlignment", "left"); %[output:253d8ace]
hold off; %[output:253d8ace]
ylabel(sprintf("%s (%s)", chanStr, unitStr)); %[output:253d8ace]
xlabel("Time from step onset (s)"); %[output:253d8ace]
title(sprintf("%s Step — %s", chanStr, fileLabel), "Interpreter", "none"); %[output:253d8ace]
legend("Location", "best"); %[output:253d8ace]
grid on; %[output:253d8ace]

% PID internals over the step window (Figure 4)
pid_tar = [];
if experiment == "speed" && has_pidt
    mask_pid = t_pidt >= t_step_start & t_pidt <= t_step_end;
    t_pid   = t_pidt(mask_pid) - t_step_start;
    pid_tar = d.PIDT_Tar(mask_pid);
    pid_act = d.PIDT_Act(mask_pid);
    pid_P   = d.PIDT_P(mask_pid);
    pid_I   = d.PIDT_I(mask_pid);
    pid_D   = d.PIDT_D(mask_pid);
    pid_FF  = d.PIDT_FF(mask_pid);
    pid_out = d.PIDT_Out(mask_pid);
elseif experiment == "yaw" && has_pids
    mask_pid = t_pids >= t_step_start & t_pids <= t_step_end;
    t_pid   = t_pids(mask_pid) - t_step_start;
    pid_tar = d.PIDS_Tar(mask_pid);
    pid_act = d.PIDS_Act(mask_pid);
    pid_P   = d.PIDS_P(mask_pid);
    pid_I   = d.PIDS_I(mask_pid);
    pid_D   = d.PIDS_D(mask_pid);
    pid_FF  = d.PIDS_FF(mask_pid);
    pid_out = pid_P + pid_I + pid_D + pid_FF;
end

if ~isempty(pid_tar) %[output:group:6682f702]
    figure(4); clf(); %[output:9cbdc88b]
    ax1 = subplot(311); %[output:9cbdc88b]
    hold on; %[output:9cbdc88b]
    plot(t_pid, pid_tar, "b--", "DisplayName", "Target"); %[output:9cbdc88b]
    plot(t_pid, pid_act, "r-",  "DisplayName", "Actual"); %[output:9cbdc88b]
    hold off; %[output:9cbdc88b]
    ylabel(sprintf("%s (%s)", chanStr, unitStr)); %[output:9cbdc88b]
    legend("Location", "best"); %[output:9cbdc88b]
    title(sprintf("%s PID Internals — Step Window", chanStr), "Interpreter", "none"); %[output:9cbdc88b]
    grid on; %[output:9cbdc88b]
    ax2 = subplot(312); %[output:9cbdc88b]
    hold on; %[output:9cbdc88b]
    plot(t_pid, pid_P,  "b-",  "DisplayName", "P"); %[output:9cbdc88b]
    plot(t_pid, pid_I,  "g-",  "DisplayName", "I"); %[output:9cbdc88b]
    plot(t_pid, pid_D,  "r-",  "DisplayName", "D"); %[output:9cbdc88b]
    plot(t_pid, pid_FF, "m--", "DisplayName", "FF"); %[output:9cbdc88b]
    hold off; %[output:9cbdc88b]
    ylabel("PID terms"); %[output:9cbdc88b]
    legend("Location", "best"); %[output:9cbdc88b]
    grid on; %[output:9cbdc88b]
    ax3 = subplot(313); %[output:9cbdc88b]
    plot(t_pid, pid_out, "k-", "DisplayName", "Output"); %[output:9cbdc88b]
    ylabel("PID output"); %[output:9cbdc88b]
    xlabel("Time from step onset (s)"); %[output:9cbdc88b]
    legend("Location", "best"); %[output:9cbdc88b]
    grid on; %[output:9cbdc88b]
    linkaxes([ax1, ax2, ax3], "x"); %[output:9cbdc88b]
end %[output:group:6682f702]
%%
%[text] ## 

function out = normalize_pwm(pwm, inzero, inmax, inmin)
    out = zeros(size(pwm));
    pos = pwm >= inzero;
    out( pos) = (pwm( pos) - inzero) / (inmax - inzero);
    out(~pos) = (pwm(~pos) - inzero) / (inzero - inmin);
end

